### 2. Update uninstall logic
In `src/commands/setup.ts`, add function:

```typescript
function removeAgentsSection(agentsPath: string): boolean {
  const content = readFileSync(agentsPath, 'utf-8');
  const startMarker = '<!-- learning-agent:start -->';
  const endMarker = '<!-- learning-agent:end -->';

  const startIdx = content.indexOf(startMarker);
  const endIdx = content.indexOf(endMarker);

  if (startIdx === -1 || endIdx === -1) return false;

  const newContent = content.slice(0, startIdx) + 
                     content.slice(endIdx + endMarker.length);
  writeFileSync(agentsPath, newContent.trim() + '\n');
  return true;
}
```

