function ensureClaudeMdReference(repoRoot: string): void {
  const claudeMdPath = join(repoRoot, '.claude', 'CLAUDE.md');
  const reference = '\n## Learning Agent\nSee @AGENTS.MD for lesson capture workflow.\n';

